<?php require_once __DIR__ . '/bootstrap/app.php'; $pdo = getDB(); $stmt = $pdo->prepare(" SELECT st.* tt.name as type_name tm.name as team_name u.full_name as employee_name FROM service_tickets st JOIN service_ticket_types tt ON st.ticket_type_id = tt.id JOIN users u ON st.employee_id = u.id LEFT JOIN service_teams tm ON st.assigned_team_id = tm.id ORDER BY st.created_at DESC\); $stmt->execute(); var_dump($stmt->fetchAll()); ?>